import{_ as t,o as i,c as o,ae as a}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Dashboard SDK Integration Guide","description":"","frontmatter":{"title":"Dashboard SDK Integration Guide","slug":"sdk-integration-tracker"},"headers":[],"relativePath":"developer-hub/sdk-integration-tracker.md","filePath":"developer-hub/sdk-integration-tracker.md"}'),r={name:"developer-hub/sdk-integration-tracker.md"};function n(l,e,s,h,d,c){return i(),o("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Integrate the Branch iOS, Android, and Web SDKs into your app or website with our Branch Dashboard integration guides. These interactive guides allow you to choose options relevant to your setup and copy and paste elements from the guide itself, all within the Branch Dashboard.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you need to revisit any of the instructions in these guides or prefer it in article format, you can view those in the <a href="./ios-sdk.html">iOS</a>, <a href="./android-sdk.html">Android</a>, or <a href="./web-sdk.html">Web SDK</a> documentation.</p></div><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>You must have or configure the following items for the relevant SDK before you can use the integration guide. You’ll see checkmarks next to configured items and exclamation points next to items that still need to be configured.</p><h4 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h4><p>Configure the following items on the <strong>App Settings</strong> page in the Branch Dashboard:</p><ul><li><a href="https://help.branch.io/docs/basic-link-configuration#3-ios-default-link-behavior" target="_blank" rel="noreferrer">Associated domains</a></li><li><a href="https://help.branch.io/docs/profile-settings#branch-key-and-secret" target="_blank" rel="noreferrer">Branch key</a> (configured by default)</li><li><a href="https://help.branch.io/docs/basic-link-configuration#3-ios-default-link-behavior" target="_blank" rel="noreferrer">iOS URI scheme</a></li><li><a href="https://help.branch.io/developers-hub/docs/ios-universal-links?highlight=universal%20links" target="_blank" rel="noreferrer">Universal links</a></li><li><a href="https://help.branch.io/developers-hub/docs/ios-universal-links#set-up-universal-links" target="_blank" rel="noreferrer">App prefix</a></li><li><a href="https://help.branch.io/developers-hub/docs/ios-universal-links#set-up-universal-links" target="_blank" rel="noreferrer">Bundle ID</a></li></ul><h4 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h4><p>Configure the following items on the <strong>App Settings</strong> page in the Branch Dashboard:</p><ul><li><a href="https://help.branch.io/docs/basic-link-configuration#2-android-default-link-behavior" target="_blank" rel="noreferrer">Associated domains</a></li><li><a href="https://help.branch.io/docs/profile-settings#branch-key-and-secret" target="_blank" rel="noreferrer">Branch key</a> (configured by default)</li><li><a href="https://help.branch.io/docs/profile-settings#branch-key-and-secret" target="_blank" rel="noreferrer">Branch secret</a> (configured by default)</li><li><a href="https://help.branch.io/docs/basic-link-configuration#2-android-default-link-behavior" target="_blank" rel="noreferrer">Android URI scheme</a></li><li><a href="https://help.branch.io/developers-hub/docs/android-app-links?highlight=android%20app%20links" target="_blank" rel="noreferrer">App links</a></li></ul><h4 id="web" tabindex="-1">Web <a class="header-anchor" href="#web" aria-label="Permalink to &quot;Web&quot;">​</a></h4><p>Configure the following items on the <strong>App Settings</strong> page in the Branch Dashboard:</p><ul><li><a href="https://help.branch.io/docs/profile-settings#branch-key-and-secret" target="_blank" rel="noreferrer">Branch key</a> (configured by default)</li><li><a href="https://help.branch.io/docs/basic-link-configuration#1-default-link-behavior" target="_blank" rel="noreferrer">Desktop fallback URL</a></li></ul><h2 id="open-an-integration-guide" tabindex="-1">Open an integration guide <a class="header-anchor" href="#open-an-integration-guide" aria-label="Permalink to &quot;Open an integration guide&quot;">​</a></h2><p>Follow these steps to open an integration guide:</p><ol><li>In the Branch Dashboard, make sure you’re on the <strong>Home</strong> page.</li><li>Find the <strong>Integrate the Branch SDK</strong> section.</li><li>Select <strong>Open an integration guide</strong>.</li><li>Select <strong>iOS</strong>, <strong>Android</strong>, or <strong>Web</strong>.</li><li>Make sure you have configured all of the required settings. Read the “Before you begin” section of this article to learn more.</li><li>Select <strong>Get Started</strong>.</li></ol><h2 id="use-the-integration-guides" tabindex="-1">Use the integration guides <a class="header-anchor" href="#use-the-integration-guides" aria-label="Permalink to &quot;Use the integration guides&quot;">​</a></h2><p>Follow the steps in the relevant integration guide to integrate the Branch SDK into your app or website.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>If you close an integration guide, you must start the guide from the beginning. Your integration progress will <strong>not</strong> be lost.</p></div><h3 id="ios-sdk-integration-guide" tabindex="-1">iOS SDK integration guide <a class="header-anchor" href="#ios-sdk-integration-guide" aria-label="Permalink to &quot;iOS SDK integration guide&quot;">​</a></h3><p>Follow the steps in the integration guide to integrate the iOS SDK into your app.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you need to revisit any of the instructions in these guides or prefer it in an article format, you can read our <a href="./ios-sdk-overview.html">iOS SDK documentation</a>.</p></div><p>In this guide, you’ll complete the following steps:</p><ol><li>Configure associated domains.</li><li>Configure <code>info.plist</code>.</li><li>Install Branch.</li><li>Initialize Branch.</li><li>Validate your integration.</li></ol><p>After you complete this setup, you’ll be able to send Branch events and deep link with Branch.</p><h3 id="android-sdk-integration-guide" tabindex="-1">Android SDK integration guide <a class="header-anchor" href="#android-sdk-integration-guide" aria-label="Permalink to &quot;Android SDK integration guide&quot;">​</a></h3><p>Follow the steps in the integration guide to integrate the Android SDK into your app.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you need to revisit any of the instructions in these guides or prefer it in an article format, you can read our <a href="./android-sdk-overview.html">Android SDK documentation</a>.</p></div><p>In this guide, you’ll complete the following steps:</p><ol><li>Install Branch.</li><li>Add dependencies.</li><li>Configure your app.</li><li>Load Branch.</li><li>Configure ProGuard.</li><li>Validate your integration.</li></ol><p>After you complete this setup, you’ll be able to send Branch events and deep link with Branch.</p><h3 id="web-sdk-integration-guide" tabindex="-1">Web SDK integration guide <a class="header-anchor" href="#web-sdk-integration-guide" aria-label="Permalink to &quot;Web SDK integration guide&quot;">​</a></h3><p>Follow the steps in the integration guide to integrate the Web SDK into your website.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you need to revisit any of the instructions in these guides or prefer it in an article format, you can read our <a href="./web-sdk-overview.html">Web SDK documentation</a>.</p></div><p>In this guide, you’ll complete the following steps:</p><ol><li>Install Branch.</li><li>Initialize Branch.</li><li>Validate your integration.</li></ol><p>After you complete this setup, you’ll be able to send Branch events and deep link with Branch.</p><h2 id="mark-the-task-complete" tabindex="-1">Mark the task complete <a class="header-anchor" href="#mark-the-task-complete" aria-label="Permalink to &quot;Mark the task complete&quot;">​</a></h2><p>Once you’ve integrated the SDKs that are relevant to your app or website, you can dismiss the section.</p><p>To do this, select the three-dot icon on the <strong>Integrate the Branch SDK</strong> section on the <strong>Home</strong> page and select <strong>Mark complete</strong>. This is a manual action to help you keep track of your progress, it does not affect your integration.</p><h2 id="additional-resources" tabindex="-1">Additional resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional resources&quot;">​</a></h2><p>For more information about integrating Branch SDKs, read our other <a href="./native-sdks-overview.html">SDK documentation</a>.</p>',43)])])}const p=t(r,[["render",n]]);export{g as __pageData,p as default};
